import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"128. Overtime","description":"","frontmatter":{"title":"128. Overtime","eba":"Mental Health Services 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/128-overtime.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/128-overtime.md"}'),i={name:"ebas/mental-health/health-professionals/hours-of-work/128-overtime.md"};function n(s,e,l,h,m,p){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_128-overtime" tabindex="-1">128. Overtime <a class="header-anchor" href="#_128-overtime" aria-label="Permalink to &quot;128. Overtime&quot;">​</a></h1><p><strong>128.1</strong> Overtime</p><p><strong>(a)</strong> The Employer may require an Employee to work reasonable overtime, and such Employee shall work overtime in accordance with such requirement.</p><p><strong>(b)</strong> An Employee may refuse to work overtime in circumstances where the working of such overtime would result in the Employee working hours which are unreasonable having regard to:</p><p><strong>(i)</strong> any risk to Employee health and safety</p><p><strong>(ii)</strong> the Employee’s personal circumstances including any family responsibilities</p><p><strong>(iii)</strong> the needs of the workplace or enterprise</p><p><strong>(iv)</strong> the notice (if any) given by the Employer of the overtime and by the Employee of their intention to refuse it; and</p><p><strong>(v)</strong> any other reasonable matter, including those specified in the Act.</p><p><strong>(c)</strong> Only overtime authorised by the Employer shall be paid for and the following rates of overtime shall apply:</p><p><strong>(i)</strong> in excess of ordinary hours of work on any one day – time and a half for the first two hours and double time thereafter</p><p><strong>(ii)</strong> outside the spread of twelve hours from the commencement of the rostered period of duty – double time</p><p><strong>(iii)</strong> outside the spread of ten hours from the commencement of work by an Employee rostered to work broken shifts – time and a half and outside the spread of twelve hours – double time</p><p><strong>(iv)</strong> in the event of an Employee being recalled to duty for any period during an off-duty period such Employee shall be paid from the time of receiving the recall until the time of returning to the place from which they were recalled with a minimum of three hours’ payment for each recall, at the following rates: A. within a spread of 12 hours from the commencement of the last previous period of ordinary duty – time and a half B. outside the spread of 12 hours from the commencement of the last period of ordinary duty – double time C. by mutual agreement with the Employer and Employee shall be allowed to take time off in lieu of overtime</p><p><strong>(d)</strong> An Employee may elect, with the consent of the Employer, to take time off in lieu of payment for overtime at a time or times agreed with the Employer, equivalent to the period worked in excess of ordinary rostered hours of duty, plus a period of time equivalent to the overtime penalty incurred. Such time in lieu shall be taken as mutually agreed between the Employer and the Employee, provided the accrual of such leave shall not extend beyond a 28-day period. The Employer shall record time off in lieu arrangements, whether under this clause, or elsewhere in this Section 3, in the time and wages book.</p><p><strong>(e)</strong> Notwithstanding anything contained in <a href="/eba/ebas/mental-health/health-professionals/classification-staffing/145-trainee-supervision.html">clause 145</a> (Trainee Supervision), any trainee may, due to medical emergency, be required to work reasonable overtime or shift duty at the discretion of the Employer. Such overtime or shift duty shall be subject to the rates and/or allowances provided elsewhere in this Section 3.</p><p><strong>128.2</strong> Transport following overtime</p><p><strong>(a)</strong> Where an Employee finishes a period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee.</p><p><strong>(b)</strong> Where overtime is a result of a double shift, the provisions below (Additional Provisions for Double Shifts) also apply.</p><p><strong>128.3</strong> Additional Provisions for Double Shifts If an Employee works a double shift (which should only occur in emergency circumstances) the following will apply to mitigate the risk of fatigue and clinical error:</p><p><strong>(a)</strong> allow breaks of at least 10 minutes’ duration in each two hours worked; and</p><p><strong>(b)</strong> adequate transport will be provided free of cost to the Employee, including the return journey where the Employee’s vehicle remains at the workplace.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',23)])])}const u=o(i,[["render",n]]);export{f as __pageData,u as default};
